update agent_client set api_secret_hash = #{apiSecretHash}, update_time = sysdate()
where agent_id = #{agentId}
and owner_user_id = #{ownerUserId}

update agent_client
nick_name = #{agent.nickName}, remark = #{agent.remark}, commission_rate = #{agent.commissionRate}, update_time = sysdate()
where agent_id = #{agent.agentId} and owner_user_id = #{ownerUserId}
